import React, { useState, useEffect } from 'react';
import './index.css'; // 确保 Tailwind 生效
import Sidebar from './components/Sidebar';
import ChatWindow from './components/ChatWindow';
import axios from 'axios';
import { themes } from './themeConfig';

const API = axios.create({ baseURL: 'http://localhost:8000' });

function App() {
  const [loggedIn, setLoggedIn] = useState(false);
  const [username, setUsername] = useState('游客');
  const [messages, setMessages] = useState([]);
  const [input, setInput] = useState('');
  const [currentTheme, setCurrentTheme] = useState('pink'); // 默认柔雾粉紫
  const [sidebarOpen, setSidebarOpen] = useState(true); // 侧边栏折叠

  const theme = themes[currentTheme];

  // 登录后加载历史
  useEffect(() => {
    if (loggedIn) {
      API.get(`/api/history?username=${username}`)
        .then(res => {
          const msgs = res.data.history.map(h => ({ sender: h.role, text: h.content }));
          setMessages(msgs);
        })
        .catch(() => {});
    }
  }, [loggedIn, username]);

  const sendMessage = async () => {
    if (!input.trim()) return;
    const userMsg = { sender: 'user', text: input };
    setMessages(prev => [...prev, userMsg]);
    setInput('');

    // 添加临时 AI 加载消息
    const loadingMsg = { sender: 'assistant', text: 'loading' };
    setMessages(prev => [...prev, loadingMsg]);

    try {
      const res = await API.post('/api/chat', {
        message: input,
        username,
        logged_in: loggedIn
      });
      // 替换 loading 消息为真实回复
      setMessages(prev => prev.slice(0, -1).concat({ sender: 'assistant', text: res.data.reply }));
    } catch (err) {
      setMessages(prev => prev.slice(0, -1).concat({ sender: 'assistant', text: '❌ 小智老师暂时不在，请稍后再试~' }));
    }
  };

  // ... 其余函数保持不变 (clearHistory, fetchMistakes, fetchReport, downloadWorksheet) 复用原逻辑

  return (
    <div className={`h-screen flex ${theme.bg} transition-all duration-500`}>
      <Sidebar
        loggedIn={loggedIn}
        username={username}
        setLoggedIn={setLoggedIn}
        setUsername={setUsername}
        onClearHistory={() => {}}
        onFetchMistakes={() => {}}
        onFetchReport={() => {}}
        onDownloadWorksheet={() => {}}
        sidebarOpen={sidebarOpen}
        setSidebarOpen={setSidebarOpen}
        currentTheme={currentTheme}
        setCurrentTheme={setCurrentTheme}
        theme={theme}
      />
      <ChatWindow
        messages={messages}
        input={input}
        setInput={setInput}
        onSend={sendMessage}
        theme={theme}
        sidebarOpen={sidebarOpen}
      />
    </div>
  );
}

export default App;
